args.sparql:
SELECT ?film ?filmLabel WHERE {
  wd:Q80966 p:P166 ?award .
  ?award ps:P166 wd:Q103618 ;
         pq:P1686 ?film ;
         pq:P585 ?date .
  ?film rdfs:label ?filmLabel .
  FILTER(LANG(?filmLabel) = "en")
  FILTER(YEAR(?date) = 2014)
}

SELECT ?film WHERE {
  wd:Q80966 p:P166 ?award .
  ?award ps:P166 wd:Q103618 ;
         pq:P1686 ?film ;
         pq:P585 ?date .
  FILTER(YEAR(?date) = 2014)
}
LIMIT 1
